    // We use a set to store all unique points generated so far (from generations 0 to k-1)
    set<Point> available_points = initial_point_set;

    // k represents the generation number we are currently trying to form (k >= 1)
    for (int k = 1; ; ++k) {
        set<Point> new_points_in_generation_k;
        vector<Point> available_points_vec(available_points.begin(), available_points.end());
        int N = available_points_vec.size();

        if (N < 2) {
            // Cannot form any new points if there are fewer than 2 distinct available points
            return -1;
        }

        // Generate new points for generation k
        for (int i = 0; i < N; ++i) {
            for (int j = i + 1; j < N; ++j) {
                const Point& a = available_points_vec[i];
                const Point& b = available_points_vec[j];

                // The problem states: "two different points".
                // Since we are iterating over the set of unique available points (available_points_vec),
                // a != b is guaranteed if i != j.
                // The problem also states: "choose two DIFFERENT points".
                // If the input set contained multiple copies of the same point, this would be tricky,
                // but the problem guarantees "Initial point set does not contain duplicate points."
