        for (const auto& new_p : new_points_in_generation_k) {
            available_points.insert(new_p);
        }

        // Safety break for extremely large searches, although constraints suggest this might not be necessary.
        // Given constraints (coords <= 6), the number of reachable points is finite and small.
        if (k > 1000) return -1; 
